function DrawGridTable() {
  const { GridTable } = components;
  const dimensionFields = ["dimension_column"];
  const measureFields = ["measure_column"];
  const fields = [
    ...dimensionFields.map((name, i) => ({
      label: name,
      id: String(i + 1),
      addedAs: i === 0 ? "row" : "column",
      floatingType: "discrete"
    })),
    ...measureFields.map((name, i) => ({
      label: name,
      id: String(dimensionFields.length + i + 1),
      addedAs: "row",
      floatingType: "continous"
    }))
  ];
  const metadataEntry = {};
  fields.forEach((field, i) => {
    metadataEntry[i + 1] = {
      name: field.label,
      type: field.floatingType === "continous" ? "numeric" : "text"
    };
  });
  const marksList = [
    {
      value: "_all_",
      id: "marks-all",
      color: { fields: [] },
      size: { fields: [] },
      label: { fields: [] },
      tooltip: { fields: [] },
      shape: { fields: [] },
      detail: { fields: [] }
    }
  ];
  const nestedReport = report.report || report;
  const gridTableProps = {
    ...report,
    data,
    fields,
    metadata: [metadataEntry],
    marksList,
    report: {
      ...nestedReport,
      reportData: {
        ...(nestedReport.reportData || {}),
        properties: {
          title: { show: false, value: "", position: "top" },
          subTitle: { show: false, value: "", position: "top" },
          format: {},
          formatColor: {},
          tooltip: { showTooltip: true },
          crosstab: {
            showGrandTotals: false,
            showRowGrandTotals: false,
            showColumnGrandTotals: false,
            showSubTotals: false,
            showRowSubTotals: false,
            showColumnSubTotals: false,
            grandTotalsPosition: "Bottom",
            crosstabCollapse: "None"
          },
          ...((nestedReport.reportData && nestedReport.reportData.properties) || {})
        }
      }
    }
  };
  return (
    <div>
      <GridTable {...gridTableProps} />
    </div>
  );
}
